/* doc-css — Shared styles for doc rendering */

/* Item references */
.hob-item-ref {
  color: var(--color-primary, #0066cc);
  background: oklch(98.5% 0.01 250);
  text-decoration: underline dashed !important;
  text-decoration-color: oklch(75% 0.06 250);
  text-underline-offset: 2px;
  cursor: pointer;
  font-family: inherit;
  font-size: inherit;
}

.hob-item-ref:hover {
  background: oklch(96% 0.02 250);
  text-decoration-color: var(--color-primary, #0066cc);
}
